var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"크헤헤, 저항해도 소용없다고.","JPN":"クヘヘ、抵抗しても無駄だ。","ENG":"Ke he he, no use resisting.","TWN":"嘿嘿嘿，反抗也沒用。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"끈질기군. 그런 실력들로 강도질이나 하는 게 아깝지도 않나?","JPN":"しつこいな。そんな腕で強盗をやっていて惜しいと思わないのか？","ENG":"How persistent. You could be using your strength to do something better than robbery, you know.","TWN":"真難纏，身手這麼好來當海盜不是很可惜嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"바다를 해치는 관리국의 개들을 내쫓는 게 우리 역할이거든.","JPN":"海を荒らす管理局の犬を追い払うのが俺たちの役目だ。","ENG":"Well, it's our job to give the boot to the Administration's dogs who are harming the ocean.","TWN":"誰叫我們的責任就是把危害大海的管理局走狗趕走。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"자, 무료로 바다를 위해 봉사하는 우리에게 순순히 환경보호비를 바치시지!","JPN":"さぁ、海のために無料でご奉仕している俺らに大人しく環境保護費を払うんだな！","ENG":"Now, why don't you surrender your donations to help save the environment to the people who are volunteering to clean the ocean?!","TWN":"我們可是自願免費守護這片大海，你就付一點環境保護費吧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"이, 이봐! 채굴기가 부서지겠어! 빨리 저 녀석들 좀 어떻게 해보라고!","JPN":"お、おい！　採掘機が壊れてしまう！　あいつらを早く何とかしろ！","ENG":"H-hey! The excavator's going to break! Do something about them!","TWN":"喂！！採礦機會壞掉的！快想辦法解決他們！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"쳇, 기다려. 애초에 우리가 가져온 건 대 침식탄이라고.","JPN":"ちっ、待て。そもそも俺たちが持ってきたのは対侵食弾だ。","ENG":"Tch, hang on. We brought anti-C.O. bullets only.","TWN":"嘖，先等一下，我們帶來的子彈都是專門對付侵蝕體的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"이렇게 된 이상 놈들이 타고 온 배를 노려야…","JPN":"こうなった以上やつらが乗ってきた船を狙うしか……","ENG":"So we're going to have to aim for the ship they brought here...","TWN":"現在只能瞄準他們搭的船…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"...Mm?","TWN":"…嗯？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어엉?","JPN":"ああん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"총성이 멈췄어. 해적놈들의 탄약이 떨어졌군. 빨리 반격하라고!","JPN":"銃声が止まった。海賊どもの弾丸が切れたようだ。早く反撃しろ！","ENG":"The shooting stopped. They're out of ammo. Shoot back, now!","TWN":"槍聲停了，他們的子彈用完了嗎？快趁現在反擊！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"쉿, 소리를 들어봐.","JPN":"しっ、音を聞いてみろ。","ENG":"Shh. Listen.","TWN":"噓，你聽。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"바다가… 울고 있어?","JPN":"海が……泣いている？","ENG":"The ocean is... crying?","TWN":"大海…在哭？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"어떻게 된 거야?","JPN":"どういうこと？","ENG":"What's happening?","TWN":"怎麼會這樣？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"이럴 리가. 아직 시기가 아닐 텐데?","JPN":"バカな。まだそんな時期じゃないはずだよな？","ENG":"No. It shouldn't be happening already...","TWN":"怎麼可能？時候不是還沒到嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야? 해적놈들이 갑자기 돌아가잖아?","JPN":"何だ？　海賊どもがいきなり帰っている？","ENG":"What? The pirates are turning back!","TWN":"怎麼搞的？那些海盜掉頭了？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"…우리도 철수해야 해! 당장!","JPN":"……俺たちも撤収するんだ！　今すぐ！","ENG":"...We need to leave! NOW!","TWN":"…我們也必須立刻離開！快！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐? 그건 안돼. 아직 채굴기도 회수하지 못했다고!","JPN":"は？　それはダメだ。まだ採掘機も回収していないんだ！","ENG":"What? No. We haven't even retrieved the excavator yet!","TWN":"什麼？那怎麼行，採礦機都還沒回收欸！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"지금은 그런 걸 신경 쓸 때가…!","JPN":"今はそんなことを気にする場合じゃ……！","ENG":"That's not what's important–!","TWN":"現在沒時間管這麼多了…！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"내… 채굴기가 바닷속으로 순식간에 잠겼어?!","JPN":"俺の……採掘機が一瞬に海の中に消えた！？","ENG":"My... excavator was just dragged underwater!","TWN":"我的… 採礦機瞬間沉到海裡了？！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"대체 방금 그건 뭐였지?","JPN":"今のはいったいなんだ？","ENG":"What was that?!","TWN":"剛剛到底發生什麼事？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DIGGER_FRONTBAY_NULL_NULL","text":{"KOREA":"이봐! 멍하니 있지 말고 대답 좀 해보라고!","JPN":"おい！　ボケっとしないで答えろ！","ENG":"Hey! Stop mucking around and answer!","TWN":"你說話啊！發什麼呆！快回答我！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"……버, 범람.","JPN":"……は、氾濫。","ENG":"...Th-the flood.","TWN":"是…洪災…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_WATCH","text":{"KOREA":"검은 범람이 시작된 거야…","JPN":"黒い氾濫が始まったんだ……","ENG":"The Black Flood is here...","TWN":"黑色洪災開始了…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMPLOYEE_FRONTBAY_NULL_ADMIN","text":{"KOREA":"심해역으로부터 대규모 급성 침식반응이 감지됐습니다.","JPN":"深海域から大規模な急性侵食反応を感知しました。","ENG":"We have detected an acute Corruption response from the deep sea area.","TWN":"目前在深海區感應到大規模的急性侵蝕反應。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이번 활동은 예정보다 빠르네요. 시니어님께서 우려하신 대로예요.","JPN":"今回の活動は予定より早いですね。シニア様が心配していた通りでした。","ENG":"This is earlier than expected. It is just as Senior's concerns.","TWN":"這次的活動比預期中來得要快，就如同Senior所擔心的一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EMPLOYEE_FRONTBAY_NULL_ADMIN","text":{"KOREA":"예상 주기보다 3개월씩이나 이릅니다. 플랜A는 물 건너갔군요.","JPN":"予想していた周期より3か月も早いです。プランAは使えなくなりましたね。","ENG":"It's 3 months earlier than the expected cycle. It seems like plan A is a no-go.","TWN":"比預期的週期早三個月左右，看來A計畫已經泡湯了。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EMPLOYEE_FRONTBAY_NULL_ADMIN","text":{"KOREA":"3단계 대피령을 내릴까요?","JPN":"3段階の退避命令を出しましょうか？","ENG":"Should we issue a level 3 evacuation notice?","TWN":"要發布第三階段的緊急避難令嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"매뉴얼대로라면 그렇게 해야겠지만…","JPN":"マニュアル通りなら、そうするべきでしょうが……","ENG":"That would be the protocol, but...","TWN":"照手冊的指示是該這麼做沒錯…"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어의 권한 없이는 대피령을 내릴 수 없습니다.","JPN":"シニアの権限がなければ退避命令は出せません。","ENG":"We cannot issue an evacuation notice without the Senior's authority.","TWN":"但是必須要有Senior的權限才能發布避難令。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EMPLOYEE_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만 2급 관리자님께선 지금 부재중이시지 않나요?","JPN":"ですが2級管理者様は今お留守ですよね？","ENG":"But, the Class 2 Administrator is currently absent, is he not?","TWN":"可是現在2級管理者不是不在嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하아… 그게 문제에요.","JPN":"はあ……それが問題です。","ENG":"*Sigh.* That is the problem.","TWN":"哀…問題就出在這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"여러분은 검은 범람의 2차 예상 피해 범위를 조사해주세요.","JPN":"皆さんは黒い氾濫の2次被害の予想範囲を調べてください。","ENG":"Please take a closer look on the secondary damage range of the Black Flood.","TWN":"請各位先協助確認黑色洪災第二波預計影響範圍。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"전 그동안 시니어님이 계실 만한 곳을 찾아 볼 테니까요.","JPN":"私はその間シニア様が居そうな場所を探してみます。","ENG":"I will search for the Senior in the meanwhile.","TWN":"我去Senior有可能會去的地方找找。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};